import React from "https://esm.sh/react@18.2.0";
import ReactDOM from "https://esm.sh/react-dom@18.2.0";

function getInitials(name) {
  if (!name) return '?';
  return name.trim().split(' ').map(n => n[0]).join('').toUpperCase().slice(0, 2);
}

function App() {
  const [model, setModel] = React.useState(appsmith.model);

  React.useEffect(() => {
    appsmith.onModelChange((newModel) => {
      setModel({ ...newModel });
    });
  }, []);

  const name = model.site_contact;
  const phone = model.contact_number;
  const email = model.contact_email;
  const hasContact = name || phone || email;

  if (!hasContact) {
    return (
      <div style={{ fontFamily: 'sans-serif', textAlign: 'center', padding: '20px 0', color: '#9ca3af', fontSize: '13px' }}>
        No site contact recorded<br/>
        <span style={{ fontSize: '11px' }}>Select a site to load contact details</span>
      </div>
    );
  }

  return (
    <div style={{ fontFamily: 'sans-serif' }}>
      <div style={{ display: 'flex', alignItems: 'center', gap: '12px', padding: '10px 12px', background: '#f9fafb', borderRadius: '6px', marginBottom: '12px' }}>
        <div style={{
          width: '40px', height: '40px', borderRadius: '50%', background: '#E1F5EE', color: '#085041',
          display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '13px', fontWeight: 600,
          flexShrink: 0, border: '1.5px solid #B6E4D4'
        }}>{getInitials(name)}</div>
        <div>
          <div style={{ fontSize: '14px', fontWeight: 600, color: '#111827' }}>{name || '—'}</div>
          <div style={{ fontSize: '12px', color: '#6b7280', marginTop: '2px' }}>Site contact — may differ from main contact</div>
        </div>
      </div>

      <div style={{ display: 'flex', alignItems: 'center', gap: '10px', padding: '8px 0', borderBottom: '0.5px solid #f3f4f6' }}>
        <div style={{ fontSize: '11px', color: '#9ca3af', textTransform: 'uppercase', width: '80px', flexShrink: 0 }}>Phone</div>
        <div style={{ fontSize: '13px', color: '#111827', fontWeight: 500 }}>
          {phone ? <a href={`tel:${phone}`} style={{ color: '#085041', textDecoration: 'none' }}>{phone}</a> : '—'}
        </div>
      </div>

      <div style={{ display: 'flex', alignItems: 'center', gap: '10px', padding: '8px 0' }}>
        <div style={{ fontSize: '11px', color: '#9ca3af', textTransform: 'uppercase', width: '80px', flexShrink: 0 }}>Email</div>
        <div style={{ fontSize: '13px', color: '#111827', fontWeight: 500 }}>
          {email ? <a href={`mailto:${email}`} style={{ color: '#085041', textDecoration: 'none' }}>{email}</a> : '—'}
        </div>
      </div>

      <div style={{ fontSize: '11px', color: '#9ca3af', marginTop: '10px' }}>
        Contact details pulled from site record — edit on the customer profile if changes are needed.
      </div>
    </div>
  );
}

appsmith.onReady(() => {
  ReactDOM.render(<App />, document.getElementById("root"));
});
